if (! function_exists('feed_watcher')) {
    function feed_watcher($url, $db_name = null, $timeout = null, $max_items = null, $force_refresh = null)
    {
        // Feed Watcher — poll RSS/Atom, diff against SQLite history, return new items
        $url = $url ?? '';
        $db_name = $db_name ?? 'feed_watcher.sqlite';
        $timeout = $timeout ?? 15;
        $max_items = $max_items ?? 100;
        $force_refresh = $force_refresh ?? false;

        if (empty($url)) {
            return ['error' => 'URL is required', 'success' => false];
        }
        $timeout = max(5, min(30, (int)$timeout));
        $max_items = max(1, min(200, (int)$max_items));

        // Fetch the feed
        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: feed_watcher/1.0\r\nAccept: application/rss+xml, application/atom+xml, application/xml, text/xml\r\n",
                'ignore_errors' => true,
            ],
            'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
        ]);

        $response = @file_get_contents($url, false, $context);
        if ($response === false) {
            $err = error_get_last();
            return ['error' => 'Failed to fetch feed: ' . ($err['message'] ?? 'unknown'), 'success' => false];
        }

        // Parse with SimpleXML
        libxml_use_internal_errors(true);
        $xml = @simplexml_load_string($response);
        if ($xml === false) {
            $errors = libxml_get_errors();
            libxml_clear_errors();
            return [
                'error' => 'Failed to parse XML',
                'xml_errors' => array_map(fn($e) => trim($e->message), array_slice($errors, 0, 5)),
                'success' => false,
            ];
        }

        // Detect RSS vs Atom
        $items = [];
        $feed_title = '';
        $feed_link = '';

        $namespaces = $xml->getNamespaces(true);

        if (isset($xml->channel->item)) {
            // RSS 2.0
            $feed_title = (string)$xml->channel->title;
            $feed_link = (string)$xml->channel->link;
            foreach ($xml->channel->item as $item) {
                // Get GUID, fall back to link + title
                $guid = '';
                if (isset($item->guid)) {
                    $guid = (string)$item->guid;
                }
                if (empty($guid) && isset($item->link)) {
                    $guid = (string)$item->link;
                }
                if (empty($guid)) {
                    $guid = (string)$item->title;
                }
                
                // Check for dc:date
                $date = '';
                if (isset($item->pubDate)) {
                    $date = (string)$item->pubDate;
                } elseif (isset($item->children('http://purl.org/dc/elements/1.1/')->date)) {
                    $date = (string)$item->children('http://purl.org/dc/elements/1.1/')->date;
                }
                
                $items[] = [
                    'guid' => $guid,
                    'title' => trim((string)$item->title),
                    'link' => (string)$item->link,
                    'date' => $date,
                    'description' => trim(mb_substr(strip_tags((string)$item->description), 0, 500)),
                ];
            }
        } elseif (isset($xml->entry)) {
            // Atom
            $feed_title = (string)$xml->title;
            if (isset($xml->link)) {
                foreach ($xml->link as $link) {
                    if ((string)$link['rel'] === 'alternate' || empty((string)$link['rel'])) {
                        $feed_link = (string)$link['href'];
                        break;
                    }
                }
            }
            
            // Check for dc:identifier in OpenSearch/other namespaced entries
            foreach ($xml->entry as $entry) {
                $guid = '';
                if (isset($entry->id)) {
                    $guid = (string)$entry->id;
                }
                if (empty($guid)) {
                    $guid = (string)$entry->title . (string)$entry->updated;
                }
                
                // Get link
                $entry_link = '';
                if (isset($entry->link)) {
                    foreach ($entry->link as $link) {
                        if ((string)$link['rel'] === 'alternate' || empty((string)$link['rel'])) {
                            $entry_link = (string)$link['href'];
                            break;
                        }
                    }
                }
                
                $items[] = [
                    'guid' => $guid,
                    'title' => trim((string)$entry->title),
                    'link' => $entry_link,
                    'date' => (string)($entry->published ?: $entry->updated ?: ''),
                    'description' => trim(mb_substr(strip_tags((string)$entry->summary ?: (string)$entry->content), 0, 500)),
                ];
            }
        } else {
            return ['error' => 'Unrecognized feed format (not RSS 2.0 or Atom)', 'success' => false];
        }

        // Limit items
        if (count($items) > $max_items) {
            $items = array_slice($items, 0, $max_items);
        }

        // Database setup
        $db_path = __DIR__ . '/../workspace/' . basename($db_name);
        $db_dir = dirname($db_path);
        if (!is_dir($db_dir)) @mkdir($db_dir, 0777, true);

        try {
            $pdo = new PDO("sqlite:$db_path");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            
            // Create tables
            $pdo->exec('CREATE TABLE IF NOT EXISTS feed_watcher_sources (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                url TEXT UNIQUE,
                feed_title TEXT,
                last_polled TEXT
            )');
            $pdo->exec('CREATE TABLE IF NOT EXISTS feed_watcher_items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                source_url TEXT,
                guid TEXT,
                title TEXT,
                link TEXT,
                date TEXT,
                description TEXT,
                first_seen TEXT,
                UNIQUE(source_url, guid)
            )');
            
            // Upsert source
            $srcStmt = $pdo->prepare('INSERT OR REPLACE INTO feed_watcher_sources (url, feed_title, last_polled) VALUES (?, ?, ?)');
            $now = gmdate('Y-m-d\TH:i:s\Z');
            $srcStmt->execute([$url, $feed_title, $now]);
            
            if ($force_refresh) {
                // Clear stored items for this source
                $delStmt = $pdo->prepare('DELETE FROM feed_watcher_items WHERE source_url = ?');
                $delStmt->execute([$url]);
            }
            
            // Get existing GUIDs for this source
            $existingStmt = $pdo->prepare('SELECT guid FROM feed_watcher_items WHERE source_url = ?');
            $existingStmt->execute([$url]);
            $existing_guids = [];
            while ($row = $existingStmt->fetch(PDO::FETCH_ASSOC)) {
                $existing_guids[$row['guid']] = true;
            }
            
            // Identify new items and store them
            $new_items = [];
            $insertStmt = $pdo->prepare(
                'INSERT OR IGNORE INTO feed_watcher_items (source_url, guid, title, link, date, description, first_seen) VALUES (?, ?, ?, ?, ?, ?, ?)'
            );
            
            foreach ($items as $item) {
                $is_new = !isset($existing_guids[$item['guid']]);
                if ($is_new) {
                    $new_items[] = $item;
                    $insertStmt->execute([$url, $item['guid'], $item['title'], $item['link'], $item['date'], $item['description'], $now]);
                }
            }
            
            // Get total tracked count
            $countStmt = $pdo->prepare('SELECT COUNT(*) as cnt FROM feed_watcher_items WHERE source_url = ?');
            $countStmt->execute([$url]);
            $total_tracked = (int)$countStmt->fetch(PDO::FETCH_ASSOC)['cnt'];
            
            // Get poll count
            $pollStmt = $pdo->prepare("SELECT COUNT(*) as cnt FROM feed_watcher_sources WHERE url = ?");
            $pollStmt->execute([$url]);
            // Actually count how many times polls have happened - just return metadata
            
            return [
                'success' => true,
                'feed_url' => $url,
                'feed_title' => $feed_title,
                'total_items_in_feed' => count($items),
                'new_items_found' => count($new_items),
                'total_tracked' => $total_tracked,
                'new_items' => array_map(function($item) {
                    return [
                        'title' => $item['title'],
                        'link' => $item['link'],
                        'date' => $item['date'],
                        'description_snippet' => mb_substr($item['description'], 0, 200),
                    ];
                }, $new_items),
                'first_poll' => ($total_tracked === count($items)),
            ];
            
        } catch (Exception $e) {
            return ['error' => 'Database error: ' . $e->getMessage(), 'success' => false];
        }
    }
}
